# Generate JS
lines = ['// 概率统计题库 — 9份真题PDF逐题录入','// 选择 | 填空 | 计算 | 证明','const PROB_STAT_QUESTIONS = [']
for i, q in enumerate(questions):
    paper, stype, qtext, opts, ans, exp = q
    o = json.dumps(opts, ensure_ascii=False)
    lines.append(f'  {{id:"z{i+1:03d}",category:"概率统计",type:"single",subtype:"{stype}",paper:"{paper}",question:{json.dumps(qtext,ensure_ascii=False)},options:{o},answer:{ans},explanation:{json.dumps(exp,ensure_ascii=False)}}},')
lines.append('];')

with open('data/prob-stat-questions.js','w',encoding='utf-8') as f:
    f.write('\n'.join(lines))

# Report
from collections import Counter
cnt = Counter(q[1] for q in questions)
print(f'Total: {len(questions)} questions')
for t in ['选择','填空','计算','证明']: print(f'  {t}: {cnt[t]}')
papers = Counter(q[0] for q in questions)
for p in sorted(papers): print(f'  Paper {p}: {papers[p]}')
